function stripInlineMarkdown(value) {
  return String(value ?? '')
    .replace(/`([^`]+)`/g, '$1')
    .replace(/\*\*([^*]+)\*\*/g, '$1')
    .replace(/__([^_]+)__/g, '$1')
    .replace(/\*([^*]+)\*/g, '$1')
    .replace(/_([^_]+)_/g, '$1')
    .replace(/\[([^\]]+)\]\(([^)]+)\)/g, '$1 ($2)');
}

function collapseSpaces(value) {
  return String(value ?? '').replace(/\s+/g, ' ').trim();
}

function normalizeCompare(value) {
  return collapseSpaces(String(value ?? ''))
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9\s:/.-]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function tokenSimilarity(a, b) {
  const ta = new Set(normalizeCompare(a).split(' ').filter((t) => t.length >= 2));
  const tb = new Set(normalizeCompare(b).split(' ').filter((t) => t.length >= 2));
  if (!ta.size && !tb.size) return 1;
  const union = new Set([...ta, ...tb]);
  let inter = 0;
  for (const token of ta) if (tb.has(token)) inter += 1;
  return union.size ? inter / union.size : 0;
}

function semanticallyEquivalent(currentValue, editedValue, minTokenSimilarity) {
  const a = normalizeCompare(currentValue);
  const b = normalizeCompare(editedValue);
  if (!a || !b) return false;
  if (a === b) return true;
  if (a.startsWith(b) || b.startsWith(a)) return true;
  if (a.includes(b) || b.includes(a)) return true;
  return tokenSimilarity(a, b) >= minTokenSimilarity;
}

function splitLines(text) {
  return String(text ?? '').replace(/\r\n/g, '\n').split('\n');
}

function collectReqMapFromMarkdown(mdText) {
  const out = new Map();
  for (const rawLine of splitLines(mdText)) {
    const plain = collapseSpaces(stripInlineMarkdown(rawLine));
    const match = plain.match(/^(REQ-\d{2,})\s*[:\-]\s*(.+)$/i);
    if (match) out.set(match[1].toUpperCase(), collapseSpaces(match[2]));
  }
  return out;
}

function collectReqMapFromPdf(text) {
  const lines = splitLines(text).map((line) => collapseSpaces(line)).filter(Boolean);
  const out = new Map();

  for (const line of lines) {
    const start = line.match(/^(REQ-\d{2,})\s*[:\-]?\s*(.*)$/i);
    if (start) {
      const reqId = start[1].toUpperCase();
      const reqValue = collapseSpaces(start[2] || '');
      if (reqValue) out.set(reqId, reqValue);
    }
  }
  return out;
}

function collectKeyValueMapFromLines(lines) {
  const out = new Map();
  for (const raw of lines) {
    const plain = collapseSpaces(stripInlineMarkdown(raw));
    if (!plain || /^REQ-\d{2,}\b/i.test(plain)) continue;
    const match = plain.match(/^([A-Za-z][A-Za-z0-9 /&()'.-]{2,50}):\s*(.+)$/);
    if (!match) continue;

    const keyDisplay = collapseSpaces(match[1]);
    const value = collapseSpaces(match[2]);
    if (!value || value.length < 2) continue;

    const keyNorm = normalizeCompare(keyDisplay);
    if (!keyNorm) continue;
    if (!out.has(keyNorm)) out.set(keyNorm, { keyDisplay, value });
  }
  return out;
}

function findLineForReqId(requirementLines, reqId) {
  const target = String(reqId ?? '').toUpperCase();
  for (let i = 0; i < requirementLines.length; i += 1) {
    const plain = collapseSpaces(stripInlineMarkdown(requirementLines[i])).toUpperCase();
    if (plain.startsWith(target + ':') || plain.startsWith(target + ' ')) return i + 1;
  }
  return null;
}

function findLineForField(requirementLines, keyDisplay) {
  const keyNorm = normalizeCompare(keyDisplay);
  for (let i = 0; i < requirementLines.length; i += 1) {
    const plain = collapseSpaces(stripInlineMarkdown(requirementLines[i]));
    const match = plain.match(/^([A-Za-z][A-Za-z0-9 /&()'.-]{2,50}):\s*(.+)$/);
    if (!match) continue;
    if (normalizeCompare(match[1]) === keyNorm) return i + 1;
  }
  return null;
}

function buildDetectedChanges(requirementsText, editedText) {
  const requirementLines = splitLines(requirementsText);
  const reqMd = collectReqMapFromMarkdown(requirementsText);
  const reqPdf = collectReqMapFromPdf(editedText);

  const kvMd = collectKeyValueMapFromLines(requirementLines);
  const kvPdf = collectKeyValueMapFromLines(splitLines(editedText));

  const changes = [];

  for (const [reqId, editedValue] of reqPdf.entries()) {
    if (!editedValue) continue;
    const currentValue = reqMd.get(reqId);
    if (!currentValue) {
      if (editedValue.length < 20 || !/\b(must|shall|should|cannot|must not|required)\b/i.test(editedValue)) {
        continue;
      }
      changes.push({
        type: 'NEW_REQ',
        anchor: reqId,
        suggestedLine: null,
        current: '[NOT PRESENT IN MARKDOWN]',
        edited: editedValue,
      });
      continue;
    }

    if (!semanticallyEquivalent(currentValue, editedValue, 0.93)) {
      changes.push({
        type: 'REQ',
        anchor: reqId,
        suggestedLine: findLineForReqId(requirementLines, reqId),
        current: currentValue,
        edited: editedValue,
      });
    }
  }

  for (const [keyNorm, editedPair] of kvPdf.entries()) {
    if (!kvMd.has(keyNorm)) continue;
    const currentPair = kvMd.get(keyNorm);
    if (!semanticallyEquivalent(currentPair.value, editedPair.value, 0.96)) {
      changes.push({
        type: 'FIELD',
        anchor: editedPair.keyDisplay,
        suggestedLine: findLineForField(requirementLines, editedPair.keyDisplay),
        current: currentPair.value,
        edited: editedPair.value,
      });
    }
  }

  const deduped = [];
  const seen = new Set();
  for (const change of changes) {
    const key = [change.type, normalizeCompare(change.anchor), normalizeCompare(change.current), normalizeCompare(change.edited)].join('|');
    if (seen.has(key)) continue;
    seen.add(key);
    deduped.push(change);
  }

  return deduped;
}

